def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(7, 0, -1):
                for b in range(1, a + 5):
                    expr = ((ratio - a)**6) / (a * b * 0.8 + 1)
                    trig = np.sin(ratio * b / (a + 1.5)) * np.cos(ratio / (b + 0.5))
                    priority += expr * trig
            exp_term = np.exp(ratio - 8)
            priority += (exp_term * np.sin(ratio * 1.3))**2 * np.tanh(ratio - 7)
        elif 5 < ratio <= 8:
            for p in range(2, int(np.ceil(ratio)) + 4):
                for q in range(1, p + 3):
                    val = ((ratio - p) ** 4) * np.cos(ratio * p / (q + 0.7)) / (q + 0.3)
                    damp = np.tanh(val) * 1.5
                    priority += damp
            priority += np.log1p(ratio) * 12 - np.tanh(ratio - 5) * 3
        elif 2 <= ratio <= 5:
            s = 0
            for r in range(1, 15):
                base = ((ratio - 2) ** r) / (r * 2.0)
                trig = np.cos(r * ratio) * np.sin(3 * ratio / (r + 0.1))
                s += base * trig
            priority = s * np.cos(10 * ratio) - np.log(ratio) * 7 + np.tanh(5 - ratio) * 2
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 12):
                s += ((2 - ratio) ** n) / (n**1.5 + 0.7) * np.sin(n * ratio * 2)
            if bin_cap < item * 1.05:
                penalty = np.sqrt(item / (bin_cap + 1)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for m in range(1, 7):
                priority += np.sin(m * ratio * i * 1.2) * ((ratio - 1) ** m) / (m + 0.5)
        elif 0.5 <= ratio < 1:
            s = 0
            for n in range(1, 18):
                s += ((1 - ratio) ** n) / (n * 3.5) * np.cos(n * item / (ratio + 0.1))
            priority = s
            if (i + int(item * 1.8)) % 5 == 0:
                priority *= np.log1p(bin_cap + 2) * 1.4
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.5) * 0.8
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 14):
                s += ((0.5 - ratio) ** k) / (k * 4) * np.cos(k * ratio * 3)
            priority = s + 1 / (bin_cap + 4)
            if int(item * 1.5) % 5 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for m in range(1, 9):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
        elif 0.05 <= ratio < 0.2:
            s = 0
            for t in range(1, 13):
                s += ((0.2 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item) % 6 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for u in range(1, 10):
                priority += ((0.2 - ratio) ** u) / (u * 8) * np.cos(item * u * 0.7)
        else:
            s = 0
            for v in range(1, 14):
                s += ((0.05 - ratio) ** v) / (v * 6) * np.sin(v * ratio * 1.2) * np.cos(v * item * 0.8)
            priority = s + 4 / (bin_cap + 6)
            if int(item * 0.9) % 7 == 0:
                priority *= 5
            else:
                priority /= 5
            if bin_cap < item * 0.07:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 3) * 6
            for w in range(1, 11):
                priority += ((0.05 - ratio) ** w) / (w * 9) * np.cos(item * w * 0.9) * np.sin(w * ratio * 1.1)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 6
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 6):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.2) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.8
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.8
        if bin_cap % 2 == 0:
            priority += np.tanh(ratio * bin_cap / (i + 1)) * 2
        else:
            priority -= np.tanh(ratio * bin_cap / (i + 1)) * 2
        priorities[i] = priority
    return priorities
